export async function POST() {
  try {
    let totalCreated = 0;
    const results: Record<string, number> = {};

    // ---- SEED DECLARATIONS ----
    const existingDecls = await db.declaration.count();
    if (existingDecls < 20) {
      if (existingDecls > 0) { await db.declaration.deleteMany(); await db.declarationCategory.deleteMany(); }
      const declCatMap = new Map<string, string>();
      for (const [slug, meta] of Object.entries(DECL_CATEGORIES)) {
        const cat = await db.declarationCategory.upsert({
          where: { slug }, update: { name: meta.name, icon: meta.icon, color: meta.color, order: meta.order },
          create: { name: meta.name, slug, icon: meta.icon, color: meta.color, order: meta.order },
        });
        declCatMap.set(slug, cat.id);
      }
      for (const item of DECLARATIONS_DATA) {
        await db.declaration.create({
          data: {
            title: item.title, slug: item.slug, description: item.description,
            summary: item.summary, content: generateDeclarationHtml(item),
            categoryId: declCatMap.get(item.categorySlug)!,
            recipientType: item.recipientType, difficulty: item.difficulty,
            tags: JSON.stringify(item.tags), applicableLaws: JSON.stringify(item.applicableLaws),
            isPublished: true, viewCount: Math.floor(Math.random() * 500) + 50,
          },
        });
        totalCreated++;
      }
      results['declarations'] = DECLARATIONS_DATA.length;
    }

    // ---- SEED POWER OF ATTORNEY ----
    const existingPoa = await db.powerOfAttorney.count();
    if (existingPoa < 10) {
      if (existingPoa > 0) { await db.powerOfAttorney.deleteMany(); await db.powerOfAttorneyCategory.deleteMany(); }
      const poaCatMap = new Map<string, string>();
      for (const [slug, meta] of Object.entries(POA_CATEGORIES)) {
        const cat = await db.powerOfAttorneyCategory.upsert({
          where: { slug }, update: { name: meta.name, icon: meta.icon, color: meta.color, order: meta.order },
          create: { name: meta.name, slug, icon: meta.icon, color: meta.color, order: meta.order },
        });
        poaCatMap.set(slug, cat.id);
      }
      for (const item of POA_DATA) {
        await db.powerOfAttorney.create({
          data: {
            title: item.title, slug: item.slug, description: item.description,
            summary: item.summary, content: generatePoaHtml(item),
            categoryId: poaCatMap.get(item.categorySlug)!,
            scope: item.scope, difficulty: item.difficulty,
            tags: JSON.stringify(item.tags), applicableLaws: JSON.stringify(item.applicableLaws),
            isPublished: true, viewCount: Math.floor(Math.random() * 400) + 30,
          },
        });
        totalCreated++;
      }
      results['powerOfAttorney'] = POA_DATA.length;
    }

    // ---- SEED LAWS ----
    const existingLaws = await db.legalLaw.count();
    if (existingLaws < 10) {
      if (existingLaws > 0) { await db.legalLaw.deleteMany(); await db.legalLawCategory.deleteMany(); }
      const lawCatMap = new Map<string, string>();
      for (const [slug, meta] of Object.entries(LAW_CATEGORIES)) {
        const cat = await db.legalLawCategory.upsert({
          where: { slug }, update: { name: meta.name, icon: meta.icon, color: meta.color, order: meta.order },
          create: { name: meta.name, slug, icon: meta.icon, color: meta.color, order: meta.order },
        });
        lawCatMap.set(slug, cat.id);
      }
      for (const item of LAWS_DATA) {
        await db.legalLaw.create({
          data: {
            title: item.title, slug: item.slug, description: item.description,
            summary: item.summary, content: generateLawHtml(item),
            categoryId: lawCatMap.get(item.categorySlug)!,
            lawNumber: item.lawNumber, lawType: item.lawType,
            approvalDate: item.approvalDate, source: item.source,
            difficulty: item.difficulty,
            tags: JSON.stringify(item.tags), applicableLaws: JSON.stringify(item.applicableLaws),
            isPublished: true, viewCount: Math.floor(Math.random() * 600) + 100,
          },
        });
        totalCreated++;
      }
      results['laws'] = LAWS_DATA.length;
    }

    // ---- SEED COURT RULINGS ----
    const existingRulings = await db.courtRuling.count();
    if (existingRulings < 10) {
      if (existingRulings > 0) { await db.courtRuling.deleteMany(); await db.courtRulingCategory.deleteMany(); }
      const rulingCatMap = new Map<string, string>();
      for (const [slug, meta] of Object.entries(RULING_CATEGORIES)) {
        const cat = await db.courtRulingCategory.upsert({
          where: { slug }, update: { name: meta.name, icon: meta.icon, color: meta.color, order: meta.order },
          create: { name: meta.name, slug, icon: meta.icon, color: meta.color, order: meta.order },
        });
        rulingCatMap.set(slug, cat.id);
      }
      for (const item of RULINGS_DATA) {
        await db.courtRuling.create({
          data: {
            title: item.title, slug: item.slug, description: item.description,
            summary: item.summary, content: generateRulingHtml(item),
            categoryId: rulingCatMap.get(item.categorySlug)!,
            rulingNumber: item.rulingNumber, rulingBranch: null,
            rulingType: item.rulingType, caseType: item.caseType,
            rulingDate: item.rulingDate, court: item.court,
            difficulty: item.difficulty,
            keywords: JSON.stringify(item.keywords),
            tags: JSON.stringify(item.tags),
            applicableLaws: JSON.stringify(item.applicableLaws),
            isPublished: true, viewCount: Math.floor(Math.random() * 300) + 20,
          },
        });
        totalCreated++;
      }
      results['courtRulings'] = RULINGS_DATA.length;
    }

    return NextResponse.json({
      message: `با موفقیت ${totalCreated} مورد در ۴ ماژول ایجاد شد`,
      total: totalCreated,
      details: results,
      seeded: true,
    });
  } catch (error) {
    console.error('Seed new modules error:', error);
    return NextResponse.json(
      { error: 'خطا در ایجاد داده‌ها', details: String(error) },
      { status: 500 }
    );
  }
}
